static inline const DragonLegacyNamedItemData* DragonFindLegacyNamedItemData (uint16_t pluginId, uint16_t itemType, uint16_t resourceId) {
	uint16_t preferredCategory = DRAGON_LEGACY_ITEM_CATEGORY_ARMOR;
	if(itemType == 1)
		preferredCategory = DRAGON_LEGACY_ITEM_CATEGORY_WEAPON;
	else if(itemType == 2)
		preferredCategory = DRAGON_LEGACY_ITEM_CATEGORY_SUMMON;
	else if(itemType == 50 or itemType == 51 or itemType == 52)
		preferredCategory = DRAGON_LEGACY_ITEM_CATEGORY_MAGIC;
	const DragonLegacyNamedItemData* fallback = NULL;
	for(int i = 0; i < kDragonLegacyNamedItemDataCount; i++) {
		if(kDragonLegacyNamedItemData[i].pluginId != pluginId or kDragonLegacyNamedItemData[i].resourceId != resourceId)
			continue;
		if(kDragonLegacyNamedItemData[i].category == preferredCategory)
			return &kDragonLegacyNamedItemData[i];
		if(fallback == NULL)
			fallback = &kDragonLegacyNamedItemData[i];
	}
	return fallback;
}

